func (gs *GameServer) cmdKick(cmd Command) {
	if !gs.hasPermission(cmd.Sender, "moderator") {
		gs.sendMessage(cmd.Sender.Conn, ServerMessage{
			Type:    "error",
			Message: "You don't have permission to use /kick. Requires moderator role.",
		})
		return
	}

	if len(cmd.Args) < 1 {
		gs.sendMessage(cmd.Sender.Conn, ServerMessage{
			Type:    "error",
			Message: "Usage: /kick <player> [reason]",
		})
		return
	}

	targetName := cmd.Args[0]
	reason := "No reason specified"
	if len(cmd.Args) > 1 {
		reason = strings.Join(cmd.Args[1:], " ")
	}

	target := gs.findPlayerByUsername(targetName)
	if target == nil {
		gs.sendMessage(cmd.Sender.Conn, ServerMessage{
			Type:    "error",
			Message: fmt.Sprintf("Player '%s' not found", targetName),
		})
		return
	}

	// Can't kick someone with equal or higher role
	if gs.hasPermission(target, cmd.Sender.Role) && target.ID != cmd.Sender.ID {
		gs.sendMessage(cmd.Sender.Conn, ServerMessage{
			Type:    "error",
			Message: "You cannot kick a player with equal or higher role",
		})
		return
	}

	// Send kick message to target
	gs.sendMessage(target.Conn, ServerMessage{
		Type:    "kicked",
		Message: fmt.Sprintf("You have been kicked by %s. Reason: %s", cmd.Sender.Username, reason),
	})

	// Close connection
	target.Conn.Close()

	// Notify server
	gs.broadcast(ServerMessage{
		Type:    "system",
		Message: fmt.Sprintf("%s was kicked by %s. Reason: %s", target.Username, cmd.Sender.Username, reason),
	}, "")

	log.Printf("KICK: %s kicked %s (Reason: %s)", cmd.Sender.Username, target.Username, reason)
}

func (gs *GameServer) cmdBan(cmd Command) {
	if !gs.hasPermission(cmd.Sender, "admin") {
		gs.sendMessage(cmd.Sender.Conn, ServerMessage{
			Type:    "error",
			Message: "You don't have permission to use /ban. Requires admin role.",
		})
		return
	}

	if len(cmd.Args) < 1 {
		gs.sendMessage(cmd.Sender.Conn, ServerMessage{
			Type:    "error",
			Message: "Usage: /ban <player> [reason]",
		})
		return
	}

	targetName := cmd.Args[0]
	reason := "No reason specified"
	if len(cmd.Args) > 1 {
		reason = strings.Join(cmd.Args[1:], " ")
	}

	target := gs.findPlayerByUsername(targetName)
	if target == nil {
		gs.sendMessage(cmd.Sender.Conn, ServerMessage{
			Type:    "error",
			Message: fmt.Sprintf("Player '%s' not found", targetName),
		})
		return
	}

	// Can't ban another admin
	if target.Role == "admin" {
		gs.sendMessage(cmd.Sender.Conn, ServerMessage{
			Type:    "error",
			Message: "You cannot ban another admin",
		})
		return
	}

	// Add to ban lists
	gs.mu.Lock()
	gs.bannedUIDs[target.ID] = true
	targetIP := target.Conn.RemoteAddr().(*net.TCPAddr).IP.String()
	gs.bannedIPs[targetIP] = true
	gs.mu.Unlock()

	// Send ban message to target
	gs.sendMessage(target.Conn, ServerMessage{
		Type:    "banned",
		Message: fmt.Sprintf("You have been banned by %s. Reason: %s", cmd.Sender.Username, reason),
	})

	// Close connection
	target.Conn.Close()

	// Notify server
	gs.broadcast(ServerMessage{
		Type:    "system",
		Message: fmt.Sprintf("%s was banned by %s. Reason: %s", target.Username, cmd.Sender.Username, reason),
	}, "")

	log.Printf("BAN: %s banned %s (ID: %s, IP: %s, Reason: %s)",
		cmd.Sender.Username, target.Username, target.ID, targetIP, reason)
}

func (gs *GameServer) cmdUnban(cmd Command) {
	if !gs.hasPermission(cmd.Sender, "admin") {
		gs.sendMessage(cmd.Sender.Conn, ServerMessage{
			Type:    "error",
			Message: "You don't have permission to use /unban. Requires admin role.",
		})
		return
	}

	if len(cmd.Args) < 1 {
		gs.sendMessage(cmd.Sender.Conn, ServerMessage{
			Type:    "error",
			Message: "Usage: /unban <player_id>",
		})
		return
	}

	targetID := cmd.Args[0]

	gs.mu.Lock()
	if gs.bannedUIDs[targetID] {
		delete(gs.bannedUIDs, targetID)
		gs.mu.Unlock()
		gs.sendMessage(cmd.Sender.Conn, ServerMessage{
			Type:    "system",
			Message: fmt.Sprintf("Player ID '%s' has been unbanned", targetID),
		})
		log.Printf("UNBAN: %s unbanned player ID %s", cmd.Sender.Username, targetID)
	} else {
		gs.mu.Unlock()
		gs.sendMessage(cmd.Sender.Conn, ServerMessage{
			Type:    "error",
			Message: fmt.Sprintf("Player ID '%s' is not banned", targetID),
		})
	}
}

func (gs *GameServer) cmdGiveItems(cmd Command) {
	if !gs.hasPermission(cmd.Sender, "moderator") {
		gs.sendMessage(cmd.Sender.Conn, ServerMessage{
			Type:    "error",
			Message: "You don't have permission to use /giveitems. Requires moderator role.",
		})
		return
	}

	if len(cmd.Args) < 2 {
		gs.sendMessage(cmd.Sender.Conn, ServerMessage{
			Type:    "error",
			Message: "Usage: /giveitems <player> <item1> [item2] ...",
		})
		return
	}

	targetName := cmd.Args[0]
	items := cmd.Args[1:]

	target := gs.findPlayerByUsername(targetName)
	if target == nil {
		gs.sendMessage(cmd.Sender.Conn, ServerMessage{
			Type:    "error",
			Message: fmt.Sprintf("Player '%s' not found", targetName),
		})
		return
	}

	gs.mu.Lock()
	target.Items = append(target.Items, items...)
	gs.mu.Unlock()

	itemList := strings.Join(items, ", ")

	gs.sendMessage(target.Conn, ServerMessage{
		Type:    "system",
		Message: fmt.Sprintf("You received items from %s: %s", cmd.Sender.Username, itemList),
	})

	gs.sendMessage(cmd.Sender.Conn, ServerMessage{
		Type:    "system",
		Message: fmt.Sprintf("Gave items to %s: %s", target.Username, itemList),
	})

	log.Printf("GIVEITEMS: %s gave [%s] to %s", cmd.Sender.Username, itemList, target.Username)
}

func (gs *GameServer) cmdTakeItems(cmd Command) {
	if !gs.hasPermission(cmd.Sender, "moderator") {
		gs.sendMessage(cmd.Sender.Conn, ServerMessage{
			Type:    "error",
			Message: "You don't have permission to use /takeitems. Requires moderator role.",
		})
		return
	}

	if len(cmd.Args) < 2 {
		gs.sendMessage(cmd.Sender.Conn, ServerMessage{
			Type:    "error",
			Message: "Usage: /takeitems <player> <item1> [item2] ...",
		})
		return
	}

	targetName := cmd.Args[0]
	itemsToRemove := cmd.Args[1:]

	target := gs.findPlayerByUsername(targetName)
	if target == nil {
		gs.sendMessage(cmd.Sender.Conn, ServerMessage{
			Type:    "error",
			Message: fmt.Sprintf("Player '%s' not found", targetName),
		})
		return
	}

	gs.mu.Lock()
	removed := []string{}
	for _, itemToRemove := range itemsToRemove {
		for i, item := range target.Items {
			if strings.EqualFold(item, itemToRemove) {
				target.Items = append(target.Items[:i], target.Items[i+1:]...)
				removed = append(removed, itemToRemove)
				break
			}
		}
	}
	gs.mu.Unlock()

	if len(removed) == 0 {
		gs.sendMessage(cmd.Sender.Conn, ServerMessage{
			Type:    "error",
			Message: fmt.Sprintf("None of the specified items found in %s's inventory", target.Username),
		})
		return
	}

	removedList := strings.Join(removed, ", ")

	gs.sendMessage(target.Conn, ServerMessage{
		Type:    "system",
		Message: fmt.Sprintf("Items removed by %s: %s", cmd.Sender.Username, removedList),
	})

	gs.sendMessage(cmd.Sender.Conn, ServerMessage{
		Type:    "system",
		Message: fmt.Sprintf("Removed items from %s: %s", target.Username, removedList),
	})

	log.Printf("TAKEITEMS: %s took [%s] from %s", cmd.Sender.Username, removedList, target.Username)
}

func (gs *GameServer) cmdInventory(cmd Command) {
	var target *Player

	if len(cmd.Args) >= 1 {
		// Check other player's inventory (moderator+)
		if !gs.hasPermission(cmd.Sender, "moderator") {
			gs.sendMessage(cmd.Sender.Conn, ServerMessage{
				Type:    "error",
				Message: "You can only check your own inventory. Moderator role required to check others.",
			})
			return
		}

		targetName := cmd.Args[0]
		target = gs.findPlayerByUsername(targetName)
		if target == nil {
			gs.sendMessage(cmd.Sender.Conn, ServerMessage{
				Type:    "error",
				Message: fmt.Sprintf("Player '%s' not found", targetName),
			})
			return
		}
	} else {
		target = cmd.Sender
	}

	gs.mu.RLock()
	items := make([]string, len(target.Items))
	copy(items, target.Items)
	gs.mu.RUnlock()

	itemList := "(empty)"
	if len(items) > 0 {
		itemList = strings.Join(items, ", ")
	}

	gs.sendMessage(cmd.Sender.Conn, ServerMessage{
		Type:    "system",
		Message: fmt.Sprintf("=== %s's Inventory ===\n%s", target.Username, itemList),
	})
}

