	log.Println(`{"type":"chat","headers":{},"body":"Hello everyone!"}`)
	log.Println(`{"type":"chat","headers":{},"body":"/kick player1 reason"}`)

	if err := server.Start(":9090"); err != nil {
		log.Fatalf("Server error: %v", err)
	}
